object Solution { private val pattern = "\\{\\{([a-zA-Z_][a-zA-Z0-9_]*)\\}\\}".r; def render_template(template: String, values: Map[String, Any]): String = pattern.replaceAllIn(template, m => values.get(m.group(1)).map(pyString).getOrElse(m.matched)); private def pyString(value: Any): String = value match { case null => "None"; case b: Boolean => if (b) "True" else "False"; case seq: Seq[_] => seq.map(pyString).mkString("[", ", ", "]"); case other => other.toString } }
